 12→
 13→// Classification holds structured metadata extracted from item content.
 14→type Classification struct {
 15→	Category    string   `json:"category"`
 16→	Topics      []string `json:"topics"`
 17→	People      []string `json:"people"`
 18→	ActionItems []string `json:"action_items"`
 19→	Sensitivity string   `json:"sensitivity_suggestion"` // "normal", "sensitive", "private"
 20→	Summary     string   `json:"summary"`
 21→}
 22→
 23→// Classifier extracts structured metadata from text content.
 24→type Classifier interface {
 25→	Classify(ctx context.Context, content string) (*Classification, error)
 26→}
 27→
 28→const (
 29→	openAIChatURL          = "https://api.openai.com/v1/chat/completions"
 30→	openAIClassifyModel    = "gpt-4o-mini"
 31→	classifyTimeout        = 60 * time.Second
 32→	maxClassifyInputLen    = 30000 // rough char limit to fit in context window
 33→	classifySystemPrompt   = `You are a metadata extraction assistant. Analyze the provided content and extract structured metadata as JSON with these fields:
 34→
 35→- "category": a single category label (e.g., "article", "note", "recipe", "meeting-notes", "tutorial", "reference", "personal", "work", "research")
 36→- "topics": array of 1-5 relevant topic tags (lowercase, hyphenated)
 37→- "people": array of people mentioned by name (empty array if none)
 38→- "action_items": array of action items or tasks mentioned (empty array if none)
 39→- "sensitivity_suggestion": one of "normal", "sensitive", or "private" based on content nature
 40→- "summary": a 1-2 sentence summary of the content
 41→
 42→Respond with ONLY valid JSON, no markdown or explanation.`
 43→)
 44→
 45→// OpenAIClassifier extracts metadata via the OpenAI Chat Completions API.
 46→type OpenAIClassifier struct {
 47→	apiKey string
 48→	model  string
 49→	client *http.Client
 50→}
 51→
 52→// OpenAIClassifierOption configures an OpenAIClassifier.
 53→type OpenAIClassifierOption func(*OpenAIClassifier)
 54→
 55→// WithClassificationModel sets a custom model name.
 56→func WithClassificationModel(model string) OpenAIClassifierOption {
 57→	return func(c *OpenAIClassifier) { c.model = model }
 58→}
 59→
 60→// WithClassificationHTTPClient sets a custom HTTP client (useful for testing).
 61→func WithClassificationHTTPClient(c *http.Client) OpenAIClassifierOption {
 62→	return func(cl *OpenAIClassifier) { cl.client = c }
 63→}
 64→
 65→// NewOpenAIClassifier creates an OpenAI-based classifier.
 66→func NewOpenAIClassifier(apiKey string, opts ...OpenAIClassifierOption) *OpenAIClassifier {
 67→	c := &OpenAIClassifier{
 68→		apiKey: apiKey,
 69→		model:  openAIClassifyModel,
 70→		client: &http.Client{Timeout: classifyTimeout},
 71→	}
 72→	for _, opt := range opts {
 73→		opt(c)
 74→	}
 75→	return c
 76→}
 77→
 78→type chatRequest struct {
 79→	Model          string        `json:"model"`
 80→	Messages       []chatMessage `json:"messages"`
 81→	ResponseFormat *respFormat   `json:"response_format,omitempty"`
 82→}
 83→
 84→type chatMessage struct {
 85→	Role    string `json:"role"`
 86→	Content string `json:"content"`
 87→}
 88→
 89→type respFormat struct {
 90→	Type string `json:"type"`
 91→}
 92→
 93→type chatResponse struct {
 94→	Choices []struct {
 95→		Message struct {
 96→			Content string `json:"content"`
 97→		} `json:"message"`
 98→	} `json:"choices"`
 99→	Error *struct {
100→		Message string `json:"message"`
101→	} `json:"error"`
102→}
103→
104→// Classify extracts structured metadata from the given content.
105→func (c *OpenAIClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
106→	if content == "" {
107→		return nil, fmt.Errorf("provider: classify: empty input")
108→	}
109→
110→	// Truncate to avoid exceeding context window
111→	if len(content) > maxClassifyInputLen {
112→		content = content[:maxClassifyInputLen]
113→	}
114→
115→	body, err := json.Marshal(chatRequest{
116→		Model: c.model,
117→		Messages: []chatMessage{
118→			{Role: "system", Content: classifySystemPrompt},
119→			{Role: "user", Content: content},
120→		},
121→		ResponseFormat: &respFormat{Type: "json_object"},
122→	})
123→	if err != nil {
124→		return nil, fmt.Errorf("provider: classify: marshal request: %w", err)
125→	}
126→
127→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openAIChatURL, bytes.NewReader(body))
128→	if err != nil {
129→		return nil, fmt.Errorf("provider: classify: build request: %w", err)
130→	}
131→	req.Header.Set("Content-Type", "application/json")
132→	req.Header.Set("Authorization", "Bearer "+c.apiKey)
133→
134→	resp, err := c.client.Do(req)
135→	if err != nil {
136→		return nil, fmt.Errorf("provider: classify: http: %w", err)
137→	}
138→	defer func() { _ = resp.Body.Close() }()
139→
140→	respBody, err := io.ReadAll(resp.Body)
141→	if err != nil {
142→		return nil, fmt.Errorf("provider: classify: read response: %w", err)
143→	}
144→
145→	if resp.StatusCode != http.StatusOK {
146→		return nil, fmt.Errorf("provider: classify: api status %d: %s", resp.StatusCode, string(respBody))
147→	}
148→
149→	var result chatResponse
150→	if err := json.Unmarshal(respBody, &result); err != nil {
151→		return nil, fmt.Errorf("provider: classify: unmarshal response: %w", err)
152→	}
153→
154→	if result.Error != nil {
155→		return nil, fmt.Errorf("provider: classify: api error: %s", result.Error.Message)
156→	}
157→
158→	if len(result.Choices) == 0 || result.Choices[0].Message.Content == "" {
159→		return nil, fmt.Errorf("provider: classify: empty response from model")
160→	}
161→
162→	var classification Classification
163→	if err := json.Unmarshal([]byte(result.Choices[0].Message.Content), &classification); err != nil {
164→		return nil, fmt.Errorf("provider: classify: parse classification json: %w", err)
165→	}
166→
167→	return &classification, nil
168→}
