 92→func TestOpenAIEmbedder_APIError(t *testing.T) {
 93→	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
 94→		w.WriteHeader(http.StatusTooManyRequests)
 95→		_, _ = w.Write([]byte(`{"error": {"message": "rate limited"}}`))
 96→	}))
 97→	defer server.Close()
 98→
 99→	embedder := NewOpenAIEmbedder("test-key")
100→	embedder.client.Transport = &urlRewriter{
101→		target:    server.URL,
102→		transport: server.Client().Transport,
103→	}
104→
105→	_, err := embedder.Embed(context.Background(), "hello")
106→	if err == nil {
107→		t.Fatal("expected error for API error response")
108→	}
109→	if !strings.Contains(err.Error(), "api status 429") {
110→		t.Errorf("expected status 429 error, got: %v", err)
111→	}
112→}
