114→func TestOpenAIEmbedder_EmptyResponse(t *testing.T) {
115→	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
116→		w.Header().Set("Content-Type", "application/json")
117→		_, _ = w.Write([]byte(`{"data": []}`))
118→	}))
119→	defer server.Close()
120→
