214→// urlRewriter is an http.RoundTripper that redirects all requests to a target URL.
215→type urlRewriter struct {
216→	target    string
217→	transport http.RoundTripper
218→}
219→
220→func (u *urlRewriter) RoundTrip(req *http.Request) (*http.Response, error) {
221→	req = req.Clone(req.Context())
222→	req.URL.Scheme = "http"
223→	req.URL.Host = strings.TrimPrefix(u.target, "http://")
224→	transport := u.transport
225→	if transport == nil {
226→		transport = http.DefaultTransport
227→	}
228→	return transport.RoundTrip(req)
229→}
