const (
	ollamaEmbeddingModel = "nomic-embed-text"
	ollamaEmbeddingDims  = 768
	ollamaEmbedTimeout   = 30 * time.Second
)

// OllamaEmbedder generates embeddings via the Ollama API.
type OllamaEmbedder struct {
	baseURL string
	model   string
	client  *http.Client
}

// OllamaEmbedderOption configures an OllamaEmbedder.
type OllamaEmbedderOption func(*OllamaEmbedder)

// WithOllamaEmbeddingModel sets a custom model name.
func WithOllamaEmbeddingModel(model string) OllamaEmbedderOption {
	return func(e *OllamaEmbedder) { e.model = model }
}

// WithOllamaEmbeddingHTTPClient sets a custom HTTP client (useful for testing).
func WithOllamaEmbeddingHTTPClient(c *http.Client) OllamaEmbedderOption {
	return func(e *OllamaEmbedder) { e.client = c }
}

// NewOllamaEmbedder creates an Ollama-based embedder.
func NewOllamaEmbedder(baseURL string, opts ...OllamaEmbedderOption) *OllamaEmbedder {
	e := &OllamaEmbedder{
		baseURL: baseURL,
		model:   ollamaEmbeddingModel,
		client:  &http.Client{Timeout: ollamaEmbedTimeout},
	}
	for _, opt := range opts {
		opt(e)
	}
	return e
}

// Dimensions returns the embedding vector size.
func (e *OllamaEmbedder) Dimensions() int { return ollamaEmbeddingDims }

type ollamaEmbedRequest struct {
	Model string `json:"model"`
	Input string `json:"input"`
}

type ollamaEmbedResponse struct {
	Embeddings [][]float32 `json:"embeddings"`
	Error      string      `json:"error,omitempty"`
}

// Embed generates a vector embedding for the given text.
func (e *OllamaEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
	if text == "" {
		return nil, fmt.Errorf("provider: ollama: embed: empty input")
	}

	if len(text) > maxEmbeddingInputLen {
		text = text[:maxEmbeddingInputLen]
	}

	body, err := json.Marshal(ollamaEmbedRequest{
		Model: e.model,
		Input: text,
	})
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: embed: marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, e.baseURL+"/api/embed", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: embed: build request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := e.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: embed: http: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: embed: read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("provider: ollama: embed: api status %d: %s", resp.StatusCode, string(respBody))
	}

	var result ollamaEmbedResponse
	if err := json.Unmarshal(respBody, &result); err != nil {
		return nil, fmt.Errorf("provider: ollama: embed: unmarshal response: %w", err)
	}

	if result.Error != "" {
		return nil, fmt.Errorf("provider: ollama: embed: api error: %s", result.Error)
	}

	if len(result.Embeddings) == 0 || len(result.Embeddings[0]) == 0 {
		return nil, fmt.Errorf("provider: ollama: embed: empty embedding in response")
	}

	return result.Embeddings[0], nil
}

