package provider

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"
)

const (
	ollamaClassifyModel   = "llama3.2"
	ollamaClassifyTimeout = 60 * time.Second
)

// OllamaClassifier extracts metadata via the Ollama Chat API.
type OllamaClassifier struct {
	baseURL string
	model   string
	client  *http.Client
}

// OllamaClassifierOption configures an OllamaClassifier.
type OllamaClassifierOption func(*OllamaClassifier)

// WithOllamaClassificationModel sets a custom model name.
func WithOllamaClassificationModel(model string) OllamaClassifierOption {
	return func(c *OllamaClassifier) { c.model = model }
}

// WithOllamaClassificationHTTPClient sets a custom HTTP client (useful for testing).
func WithOllamaClassificationHTTPClient(c *http.Client) OllamaClassifierOption {
	return func(c *OllamaClassifier) { c.client = c }
}

// NewOllamaClassifier creates an Ollama-based classifier.
func NewOllamaClassifier(baseURL string, opts ...OllamaClassifierOption) *OllamaClassifier {
	c := &OllamaClassifier{
		baseURL: baseURL,
		model:   ollamaClassifyModel,
		client:  &http.Client{Timeout: ollamaClassifyTimeout},
	}
	for _, opt := range opts {
		opt(c)
	}
	return c
}

type ollamaChatRequest struct {
	Model    string        `json:"model"`
	Messages []chatMessage `json:"messages"`
	Format   string        `json:"format"`
	Stream   bool          `json:"stream"`
}

type ollamaChatResponse struct {
	Message struct {
		Content string `json:"content"`
	} `json:"message"`
	Error string `json:"error,omitempty"`
}

// Classify extracts structured metadata from the given content.
func (c *OllamaClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
	if content == "" {
		return nil, fmt.Errorf("provider: ollama: classify: empty input")
	}

	if len(content) > maxClassifyInputLen {
		content = content[:maxClassifyInputLen]
	}

	body, err := json.Marshal(ollamaChatRequest{
		Model: c.model,
		Messages: []chatMessage{
			{Role: "system", Content: classifySystemPrompt},
			{Role: "user", Content: content},
		},
		Format: "json",
		Stream: false,
	})
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.baseURL+"/api/chat", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: build request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := c.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: http: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("provider: ollama: classify: api status %d: %s", resp.StatusCode, string(respBody))
	}

	var result ollamaChatResponse
	if err := json.Unmarshal(respBody, &result); err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: unmarshal response: %w", err)
	}

	if result.Error != "" {
		return nil, fmt.Errorf("provider: ollama: classify: api error: %s", result.Error)
	}

	if result.Message.Content == "" {
		return nil, fmt.Errorf("provider: ollama: classify: empty response from model")
	}

	var classification Classification
	if err := json.Unmarshal([]byte(result.Message.Content), &classification); err != nil {
		return nil, fmt.Errorf("provider: ollama: classify: parse classification json: %w", err)
	}

	return &classification, nil
}

package provider

import (
	"context"
	"fmt"
	"strings"
	"testing"
)

// mockEmbedder is a test double for the Embedder interface.
type mockEmbedder struct {
	name string
	dims int
}

func (m *mockEmbedder) Embed(_ context.Context, text string) ([]float32, error) {
	if text == "" {
		return nil, fmt.Errorf("empty input")
	}
	vec := make([]float32, m.dims)
	vec[0] = float32(m.dims) // encode dims as first value so tests can identify which provider was used
	return vec, nil
}

func (m *mockEmbedder) Dimensions() int { return m.dims }

// mockClassifier is a test double for the Classifier interface.
type mockClassifier struct {
	name string
}

func (m *mockClassifier) Classify(_ context.Context, content string) (*Classification, error) {
	if content == "" {
		return nil, fmt.Errorf("empty input")
	}
	return &Classification{
		Category: m.name,
		Summary:  "classified by " + m.name,
	}, nil
}

func TestRoutingEmbedder_NormalUsesDefault(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	localEmb := &mockEmbedder{name: "local", dims: 768}
	router := NewRoutingEmbedder(defaultEmb, localEmb)

	vec, err := router.EmbedWithSensitivity(context.Background(), "hello", "normal")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if vec[0] != 1536 {
		t.Errorf("expected default provider (1536), got %v", vec[0])
	}
}

func TestRoutingEmbedder_SensitiveUsesLocal(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	localEmb := &mockEmbedder{name: "local", dims: 768}
	router := NewRoutingEmbedder(defaultEmb, localEmb)

	for _, sensitivity := range []string{"sensitive", "private"} {
		vec, err := router.EmbedWithSensitivity(context.Background(), "hello", sensitivity)
		if err != nil {
			t.Fatalf("unexpected error for %s: %v", sensitivity, err)
		}
		if vec[0] != 768 {
			t.Errorf("expected local provider (768) for %s, got %v", sensitivity, vec[0])
		}
	}
}

func TestRoutingEmbedder_NilLocalFallsBack(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	router := NewRoutingEmbedder(defaultEmb, nil)

	vec, err := router.EmbedWithSensitivity(context.Background(), "hello", "sensitive")
	if err != nil {
